  static Surah byNumber(int n) => all.firstWhere((Surah s) => s.number == n);

  static List<Surah> search(String query) {
    if (query.trim().isEmpty) return all;
    final String q = query.toLowerCase().trim();
    return all.where((Surah s) {
      return s.nameTransliteration.toLowerCase().contains(q) ||
          s.nameEnglish.toLowerCase().contains(q) ||
          s.meaning.toLowerCase().contains(q) ||
          s.number.toString() == q ||
          s.nameArabic.contains(q);
    }).toList();
  }
}
